const raw = $input.first().json.output[0].content[0].text;
const products = JSON.parse(raw);

return products.map(p => ({ json: p }));

const input = $input.first().json;
const product = $('Loop Over Items').item.json;
const results = input.images_results || [];

// ─── Empty results ───────────────────────────────────────────
if (results.length === 0) {
  return [{
    json: {
      totalHits: 0,
      download_url: '',
      fallback_url_1: '',
      fallback_url_2: '',
      image_source_site: 'none',
      image_title: '',
      name: product.name,
      safe_name: product.safe_name,
      image_search_query: product.image_search_query,
      category: product.category || product.Categories,
      price: product.price || product['Regular price'],
      short_description: product.short_description,
      long_description: product.long_description,
      size: product.size,
      color: product.color,
      material: product.material,
      weight: product.weight,
      dimensions: product.dimensions,
      features: product.features,
      industry_use: product.industry_use || product.industry_notes,
      attribute_2_name: product.attribute_2_name || '',
      attribute_2_values: product.attribute_2_values || '',
      attribute_3_name: product.attribute_3_name || '',
      attribute_3_values: product.attribute_3_values || '',
      attribute_4_name: product.attribute_4_name || '',
      attribute_4_values: product.attribute_4_values || '',
      attribute_5_name: product.attribute_5_name || '',
      attribute_5_values: product.attribute_5_values || '',
      attribute_6_name: product.attribute_6_name || '',
      attribute_6_values: product.attribute_6_values || '',
      attribute_7_name: product.attribute_7_name || '',
      attribute_7_values: product.attribute_7_values || '',
      attribute_8_name: product.attribute_8_name || '',
      attribute_8_values: product.attribute_8_values || ''
    }
  }];
}

// ─── Blacklisted sources ──────────────────────────────────────
const blacklistSources = [
  // Paid watermark stock sites
  'shutterstock', 'getty', 'alamy', 'istockphoto',
  'dreamstime', 'depositphotos', '123rf', 'adobe.com',
  // Watermark free sites
  'pngtree', 'freepik', 'vecteezy', 'canstockphoto',
  'clipartmax', 'cleanpng', 'pngwing', 'kindpng',
  // eCommerce / Cloudflare blocked
  'brambleberry', 'demandware', 'myshopify',
  'bigcommerce', 'squarespace', 'wixstatic',
  'shopify', 'walmart', 'amazon', 'ebay',
  'etsy', 'alibaba', 'flipkart', 'target',
  // Social media auth-required CDNs
  'fbsbx.com', 'facebook.com', 'instagram.com',
  'cdninstagram.com', 'pinimg.com', 'twimg.com',
  'tiktokcdn.com', 'snapchat.com', 'linkedin.com',
  'lnkd.in'
];

// ─── Blacklisted URL patterns ─────────────────────────────────
const blacklistUrlPatterns = [
  // Watermark sites
  'pngtree.com', 'freepik.com', 'vecteezy.com',
  'pngwing.com', 'kindpng.com', 'cleanpng.com',
  // Watermark indicators
  'watermark', '_preview.', '-preview.', 'comp_',
  // Social media auth patterns
  'lookaside.fbsbx', 'media_id=', 'fbcdn',
  'scontent.', 'cdninstagram', 'pinimg',
  'auth_token=', 'access_token=', '?media_id',
  // Broken/unreliable CDN patterns
  'nitrocdn.com',       // Nitro CDN - often 404
  'optimized/rev-',     // Nitro optimized - often broken
  // Non-image page patterns
  '.html', '.php', '.asp', '.jsp',
  // Private/restricted
  'private', 'restricted', 'protected',
   'lemon8-app.com',     // ← add
  'lemon8.com',         // ← add
  'tiktok.com',         // ← add
  'bytedance.com'
];

// ─── Preferred clean royalty-free sources ─────────────────────
const preferredSources = [
  'unsplash.com', 'pexels.com', 'pixabay.com',
  'stocksnap.io', 'rawpixel.com', 'reshot.com',
  'lifeofpix.com', 'picjumbo.com', 'kaboompics.com',
  'burst.shopify', 'negativespace.co', 'gratisography.com'
];

// ─── URL validator ────────────────────────────────────────────
function isValidImageUrl(url) {
  if (!url || typeof url !== 'string') return false;
  const lower = url.toLowerCase();

  // Must start with http
  if (!lower.startsWith('http')) return false;

  // Reject auth/social CDN patterns
  const authPatterns = [
    'lookaside.fbsbx', 'media_id=', 'fbcdn',
    'scontent.', 'cdninstagram', 'pinimg',
    'auth_token=', 'access_token=', '?media_id',
    'nitrocdn.com', 'optimized/rev-'
  ];
  if (authPatterns.some(p => lower.includes(p))) return false;

  // Reject HTML pages
  const urlWithoutParams = lower.split('?')[0];
  const badExtensions = ['.html', '.htm', '.php', '.asp', '.jsp'];
  if (badExtensions.some(ext => urlWithoutParams.endsWith(ext))) return false;

  return true;
}

// ─── Filter clean images ──────────────────────────────────────
const clean = results.filter(img => {
  const source = (img.source || '').toLowerCase();
  const original = (img.original || '').toLowerCase();
  const thumbnail = (img.thumbnail || '').toLowerCase();
  const title = (img.title || '').toLowerCase();

  // Reject blacklisted sources
  if (blacklistSources.some(bad =>
    source.includes(bad) || original.includes(bad)
  )) return false;

  // Reject blacklisted URL patterns
  if (blacklistUrlPatterns.some(pattern =>
    original.includes(pattern) || thumbnail.includes(pattern)
  )) return false;

  // Reject branded/copyright titles
  if (
    title.includes('™') || title.includes('®') ||
    title.includes('©') || title.includes('watermark')
  ) return false;

  // Must have at least one valid downloadable URL
  if (!isValidImageUrl(img.thumbnail) && !isValidImageUrl(img.original)) return false;

  return true;
});

// ─── Prioritize preferred clean sources ───────────────────────
const preferred = clean.filter(img => {
  const source = (img.source || '').toLowerCase();
  const link = (img.original || '').toLowerCase();
  return preferredSources.some(good =>
    source.includes(good) || link.includes(good)
  );
});

// ─── Final pool — priority order ─────────────────────────────
const pool = preferred.length > 0 ? preferred
           : clean.length > 0 ? clean
           : results;

// ─── Pick best valid URL per image ───────────────────────────
function getBestUrl(img) {

  // Original sometime Cloudflare blocked
  if (isValidImageUrl(img.original)) return img.original;
  // Thumbnail as fallback
    if (isValidImageUrl(img.thumbnail)) return img.thumbnail;

  return '';
}

// ─── Get top 3 valid images as fallbacks ─────────────────────
const top3 = pool
  .map(img => ({
    url: getBestUrl(img),
    source: img.source || '',
    title: img.title || ''
  }))
  .filter(item => item.url !== '')
  .slice(0, 3);

const best = top3[0] || { url: '', source: '', title: '' };

// ─── Final output ─────────────────────────────────────────────
return [{
  json: {
    totalHits: pool.length,

    // Primary + 2 fallback URLs
    download_url: best.url,
    fallback_url_1: top3[1]?.url || '',
    fallback_url_2: top3[2]?.url || '',

    image_source_site: best.source,
    image_title: best.title,

    // Product fields
    name: product.name,
    image_search_query: product.image_search_query,
    category: product.category || product.Categories,
    price: product.price || product['Regular price'],
    short_description: product.short_description,
    long_description: product.long_description,
    size: product.size,
    color: product.color,
    material: product.material,
    weight: product.weight,
    dimensions: product.dimensions,
    features: product.features,
    industry_use: product.industry_use || product.industry_notes,

    // Dynamic attributes
    attribute_2_name: product.attribute_2_name || '',
    attribute_2_values: product.attribute_2_values || '',
    attribute_3_name: product.attribute_3_name || '',
    attribute_3_values: product.attribute_3_values || '',
    attribute_4_name: product.attribute_4_name || '',
    attribute_4_values: product.attribute_4_values || '',
    attribute_5_name: product.attribute_5_name || '',
    attribute_5_values: product.attribute_5_values || '',
    attribute_6_name: product.attribute_6_name || '',
    attribute_6_values: product.attribute_6_values || '',
    attribute_7_name: product.attribute_7_name || '',
    attribute_7_values: product.attribute_7_values || '',
    attribute_8_name: product.attribute_8_name || '',
    attribute_8_values: product.attribute_8_values || ''
  }
}];

const input = $input.first().json;
const product = $('Loop Over Items').item.json;

const fileId = input.id || null;
const driveUrl = fileId
  ? `https://drive.google.com/file/d/${fileId}/view`
  : 'UPLOAD_FAILED';

return [{
  json: {
    ...product,
    drive_url: driveUrl,
    image_source: 'serpapi'
  }
}];
